// 1. Eventos culturales
let eventsData = [];
try {
  const rawResp = $('Fetch Cultural Events').first().json;
  // Detect Cloudflare challenge page (returns HTML instead of JSON)
  const isCloudflare = typeof rawResp === 'string' || rawResp?.statusCode === 403 || (rawResp && Object.keys(rawResp).some(k => rawResp[k] && typeof rawResp[k] === 'string' && rawResp[k].includes('Cloudflare')));
  const raw = isCloudflare ? [] : rawResp;
  if (Array.isArray(raw)) eventsData = raw;
  else if (raw && Array.isArray(raw.data)) eventsData = raw.data;
  else if (raw && Array.isArray(raw.events)) eventsData = raw.events;
} catch(e) { eventsData = []; }

let eventsSummary = '';
if (eventsData.length === 0) {
  eventsSummary = 'No se encontraron eventos activos. Recomendá visitar agendaculturalsmt.com';
} else {
  const now = new Date();
  const upcoming = eventsData
    .filter(ev => { const d = new Date(ev.date || ev.fecha || ev.start_date || now); return (d - now) >= -86400000 && (d - now) <= 30 * 86400000; })
    .slice(0, 10);
  if (upcoming.length === 0) {
    eventsSummary = 'No hay eventos próximos via API. Recomendá visitar agendaculturalsmt.com';
  } else {
    eventsSummary = upcoming.map(ev => {
      const nombre = ev.title || ev.nombre || ev.name || 'Evento';
      const fecha = ev.date || ev.fecha || ev.start_date || '';
      const lugar = ev.location || ev.lugar || ev.venue || '';
      const desc = ev.description || ev.descripcion || ev.summary || '';
      const dateStr = fecha ? new Date(fecha).toLocaleDateString('es-AR', {weekday:'long', day:'2-digit', month:'long'}) : '';
      return `• ${nombre}${dateStr ? ' — ' + dateStr : ''}${lugar ? ' @ ' + lugar : ''}${desc ? ': ' + desc.substring(0,100) : ''}`;
    }).join('\n');
  }
}

// 2. FAQs dinámicas desde Supabase
let faqsSummary = '';
try {
  const allItems = $('Fetch FAQs').all();
  const faqsArr = allItems.length > 0 ? allItems.map(i => i.json) : [];
  if (faqsArr.length > 0) {
    const catLabels = {
      excursiones:'EXCURSIONES', transporte:'TRANSPORTE', gastronomia:'GASTRONOMÍA',
      alojamiento:'ALOJAMIENTO', atracciones:'ATRACCIONES', servicios:'SERVICIOS',
      nocturna:'VIDA NOCTURNA', salud:'SALUD', compras:'COMPRAS', festivales:'FESTIVALES', general:'GENERAL'
    };
    const groups = {};
    faqsArr.forEach(f => {
      const cat = f.categoria || 'general';
      if (!groups[cat]) groups[cat] = [];
      groups[cat].push(f);
    });
    faqsSummary = Object.entries(groups).map(([cat, items]) => {
      const label = catLabels[cat] || cat.toUpperCase();
      const qs = items.map(f => `  P: ${f.pregunta}\n  R: ${f.respuesta}`).join('\n');
      return `[${label}]\n${qs}`;
    }).join('\n\n');
  }
} catch(e) { faqsSummary = ''; }

return [{ json: {
  events_summary: eventsSummary,
  faqs_summary: faqsSummary,
  events_count: eventsData.length,
  last_input_text: $('Webhook').first().json.body.last_input_text || '',
  whatsapp_phone: $('Webhook').first().json.body.whatsapp_phone || '',
  user_name: $('Webhook').first().json.body.name || '',
  subscriber_id: $('Webhook').first().json.body.id || '',
  session_key: $('Webhook').first().json.body.key || '',
  live_chat_url: $('Webhook').first().json.body.live_chat_url || ''
}}];

// Extrae la respuesta de texto de OpenRouter y la formatea como output del agente
const resp = $input.first().json;
let text = '';
try {
  text = resp.choices?.[0]?.message?.content || resp.error?.message || 'No pude analizar la imagen.';
} catch(e) { text = 'Error al procesar la imagen.'; }

return [{ json: {
  output: {
    intent: 'geo_quiz',
    language: 'es',
    cuisine_type: null,
    budget: null,
    origen_provincia: null,
    medio_transporte: null,
    has_photo: true,
    additional_info: text
  }
}}];

