const originalInput = $('¿Es un audio?').first().json;
const resp = $input.first().json;
let text = '';

try {
  text = resp.choices?.[0]?.message?.content || resp.error?.message || '';
} catch(e) {}

if (!text || text.trim() === '') {
  text = '[El audio recibido está vacío o no pudo ser transcrito]';
}

// Inyectar el texto como si el usuario lo hubiera escrito
originalInput.last_input_text = text;

return [{ json: originalInput }];
